import React, { useState } from 'react';
import { 
  Search, 
  Filter, 
  Plus, 
  MoreHorizontal,
  Mail,
  Phone,
  Calendar,
  MapPin,
  Edit,
  Trash2,
  UserPlus,
  Shield,
  Clock,
  CheckCircle,
  XCircle,
  AlertCircle,
  Users
} from 'lucide-react';
import { usersData } from '../../data/usersData';
import TopTabs from '../dashboard/TopTabs';
import LiveNotifications from '../shared/LiveNotifications';
import ActionBar from '../dashboard/ActionBar';
import UserDetails from './UserDetails';

const TeamPage = ({ onNavigate }) => {
  const [selectedUser, setSelectedUser] = useState(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterRole, setFilterRole] = useState('all');
  const [filterStatus, setFilterStatus] = useState('all');
  const [showFilters, setShowFilters] = useState(false);
  const [sortBy, setSortBy] = useState('name');
  const [selectedUsers, setSelectedUsers] = useState([]);

  // Tabs para gestão de usuários
  const tabs = [
    { id: 'all', label: 'All Users', count: usersData.length },
    { id: 'active', label: 'Active', count: usersData.filter(u => u.status === 'active').length },
    { id: 'inactive', label: 'Inactive', count: usersData.filter(u => u.status === 'inactive').length },
    { id: 'pending', label: 'Pending', count: usersData.filter(u => u.status === 'pending').length }
  ];

  const [activeTab, setActiveTab] = useState('all');

  // Filtrar usuários baseado na busca, filtros e tab ativa
  const filteredUsers = usersData.filter(user => {
    const matchesSearch = user.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         user.email.toLowerCase().includes(searchTerm.toLowerCase());

    const matchesRole = filterRole === 'all' || user.role === filterRole;
    const matchesStatus = filterStatus === 'all' || user.status === filterStatus;
    const matchesTab = activeTab === 'all' || user.status === activeTab;

    return matchesSearch && matchesRole && matchesStatus && matchesTab;
  });

  // Ordenar usuários
  const sortedUsers = [...filteredUsers].sort((a, b) => {
    switch (sortBy) {
      case 'name':
        return a.name.localeCompare(b.name);
      case 'role':
        return a.role.localeCompare(b.role);
      case 'status':
        return a.status.localeCompare(b.status);
      case 'lastActive':
        return new Date(b.lastActive) - new Date(a.lastActive);
      default:
        return 0;
    }
  });

  const handleUserClick = (user) => {
    setSelectedUser(user);
  };

  const handleSelectUser = (userId) => {
    setSelectedUsers(prev => 
      prev.includes(userId) 
        ? prev.filter(id => id !== userId)
        : [...prev, userId]
    );
  };

  const handleSelectAll = () => {
    if (selectedUsers.length === sortedUsers.length) {
      setSelectedUsers([]);
    } else {
      setSelectedUsers(sortedUsers.map(user => user.id));
    }
  };

  const getStatusIcon = (status) => {
    switch (status) {
      case 'active':
        return <CheckCircle className="h-4 w-4 text-green-500" />;
      case 'inactive':
        return <XCircle className="h-4 w-4 text-red-500" />;
      case 'pending':
        return <AlertCircle className="h-4 w-4 text-yellow-500" />;
      default:
        return <AlertCircle className="h-4 w-4 text-gray-500" />;
    }
  };

  const getStatusColor = (status) => {
    switch (status) {
      case 'active':
        return 'bg-green-100 text-green-800';
      case 'inactive':
        return 'bg-red-100 text-red-800';
      case 'pending':
        return 'bg-yellow-100 text-yellow-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  const getRoleColor = (role) => {
    switch (role) {
      case 'admin':
        return 'bg-purple-100 text-purple-800';
      case 'manager':
        return 'bg-blue-100 text-blue-800';
      case 'user':
        return 'bg-gray-100 text-gray-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  return (
    <div className="flex h-full">
      {/* Main Content */}
      <div className={`flex-1 flex flex-col ${selectedUser ? 'mr-80' : ''}`}>
        {/* Top Bar with Tabs, Live Notifications and Actions */}
        <div className="flex items-center justify-between p-4 border-b border-neutral-700">
          <TopTabs 
            tabs={tabs}
            activeTab={activeTab}
            onTabChange={setActiveTab}
          />
          <div className="flex items-center space-x-4">
            <LiveNotifications 
              usersData={usersData} 
              onUserClick={handleUserClick}
            />
            <ActionBar 
              selectedCount={selectedUsers.length}
              onAction={(action) => console.log('Action:', action)}
              actions={[
                { id: 'activate', label: 'Activate Users', icon: CheckCircle },
                { id: 'deactivate', label: 'Deactivate Users', icon: XCircle },
                { id: 'delete', label: 'Delete Users', icon: Trash2, destructive: true }
              ]}
            />
          </div>
        </div>

        {/* Search and Filters */}
        <div className="p-4 border-b border-neutral-700">
          <div className="flex items-center space-x-4">
            <div className="flex-1 relative">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-neutral-400" />
              <input
                type="text"
                placeholder="Search users by name or email..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full pl-10 pr-4 py-2 bg-neutral-800 border border-neutral-700 rounded-lg text-white placeholder-neutral-400 focus:outline-none focus:border-blue-500"
              />
            </div>

            <div className="relative">
              <button
                onClick={() => setShowFilters(!showFilters)}
                className="flex items-center space-x-2 px-4 py-2 bg-neutral-800 border border-neutral-700 rounded-lg text-white hover:bg-neutral-700 transition-colors"
              >
                <Filter className="h-4 w-4" />
                <span>Filters</span>
              </button>

              {showFilters && (
                <div className="absolute right-0 top-full mt-2 w-64 bg-neutral-800 border border-neutral-700 rounded-lg shadow-xl z-50">
                  <div className="p-4 space-y-4">
                    <div>
                      <label className="block text-sm font-medium text-white mb-2">Role</label>
                      <select
                        value={filterRole}
                        onChange={(e) => setFilterRole(e.target.value)}
                        className="w-full bg-neutral-700 border border-neutral-600 rounded-lg px-3 py-2 text-white"
                      >
                        <option value="all">All Roles</option>
                        <option value="admin">Admin</option>
                        <option value="manager">Manager</option>
                        <option value="user">User</option>
                      </select>
                    </div>

                    <div>
                      <label className="block text-sm font-medium text-white mb-2">Status</label>
                      <select
                        value={filterStatus}
                        onChange={(e) => setFilterStatus(e.target.value)}
                        className="w-full bg-neutral-700 border border-neutral-600 rounded-lg px-3 py-2 text-white"
                      >
                        <option value="all">All Status</option>
                        <option value="active">Active</option>
                        <option value="inactive">Inactive</option>
                        <option value="pending">Pending</option>
                      </select>
                    </div>

                    <div>
                      <label className="block text-sm font-medium text-white mb-2">Sort By</label>
                      <select
                        value={sortBy}
                        onChange={(e) => setSortBy(e.target.value)}
                        className="w-full bg-neutral-700 border border-neutral-600 rounded-lg px-3 py-2 text-white"
                      >
                        <option value="name">Name</option>
                        <option value="role">Role</option>
                        <option value="status">Status</option>
                        <option value="lastActive">Last Active</option>
                      </select>
                    </div>
                  </div>
                </div>
              )}
            </div>

            <button className="flex items-center space-x-2 px-4 py-2 bg-blue-600 hover:bg-blue-700 rounded-lg text-white transition-colors">
              <UserPlus className="h-4 w-4" />
              <span>Add User</span>
            </button>
          </div>
        </div>

        {/* Users Table */}
        <div className="flex-1 overflow-auto">
          <table className="w-full">
            <thead className="bg-neutral-800 sticky top-0">
              <tr>
                <th className="w-12 p-4">
                  <input
                    type="checkbox"
                    checked={selectedUsers.length === sortedUsers.length && sortedUsers.length > 0}
                    onChange={handleSelectAll}
                    className="rounded border-neutral-600 bg-neutral-700 text-blue-600 focus:ring-blue-500"
                  />
                </th>
                <th className="text-left p-4 text-sm font-medium text-neutral-300">User</th>
                <th className="text-left p-4 text-sm font-medium text-neutral-300">Role</th>
                <th className="text-left p-4 text-sm font-medium text-neutral-300">Status</th>
                <th className="text-left p-4 text-sm font-medium text-neutral-300">Last Active</th>
                <th className="text-left p-4 text-sm font-medium text-neutral-300">Actions</th>
              </tr>
            </thead>
            <tbody>
              {sortedUsers.map((user) => (
                <tr 
                  key={user.id}
                  className="border-b border-neutral-700 hover:bg-neutral-800/50 cursor-pointer"
                  onClick={() => handleUserClick(user)}
                >
                  <td className="p-4">
                    <input
                      type="checkbox"
                      checked={selectedUsers.includes(user.id)}
                      onChange={(e) => {
                        e.stopPropagation();
                        handleSelectUser(user.id);
                      }}
                      className="rounded border-neutral-600 bg-neutral-700 text-blue-600 focus:ring-blue-500"
                    />
                  </td>
                  <td className="p-4">
                    <div className="flex items-center space-x-3">
                      <img
                        src={user.avatar}
                        alt={user.name}
                        className="w-10 h-10 rounded-full object-cover"
                      />
                      <div>
                        <div className="font-medium text-white">{user.name}</div>
                        <div className="text-sm text-neutral-400">{user.email}</div>
                      </div>
                    </div>
                  </td>
                  <td className="p-4">
                    <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${getRoleColor(user.role)}`}>
                      {user.role}
                    </span>
                  </td>
                  <td className="p-4">
                    <div className="flex items-center space-x-2">
                      {getStatusIcon(user.status)}
                      <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${getStatusColor(user.status)}`}>
                        {user.status}
                      </span>
                    </div>
                  </td>
                  <td className="p-4 text-sm text-neutral-400">
                    {user.lastActive ? new Date(user.lastActive).toLocaleDateString() : 'Never'}
                  </td>
                  <td className="p-4">
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        // Handle action menu
                      }}
                      className="p-2 hover:bg-neutral-700 rounded-lg transition-colors"
                    >
                      <MoreHorizontal className="h-4 w-4 text-neutral-400" />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>

          {sortedUsers.length === 0 && (
            <div className="flex flex-col items-center justify-center py-12">
              <div className="text-neutral-400 text-center">
                <Users className="h-12 w-12 mx-auto mb-4 opacity-50" />
                <h3 className="text-lg font-medium mb-2">No users found</h3>
                <p className="text-sm">Try adjusting your search or filters</p>
              </div>
            </div>
          )}
        </div>
      </div>

      {/* User Details Panel */}
      {selectedUser && (
        <UserDetails 
          user={selectedUser}
          onClose={() => setSelectedUser(null)}
          onEdit={(user) => console.log('Edit user:', user)}
          onDelete={(user) => console.log('Delete user:', user)}
        />
      )}
    </div>
  );
};

export default TeamPage;
